export function slugify(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');
}

export function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

export interface User {
  id: string;
  name: string;
  createdAt: Date;
}

export interface Post {
  id: string;
  title: string;
  body: string;
  publishedAt: Date;
}
